'use client';

import { useMemo, useState } from 'react';
import { CalendarEventDto } from '@soenglish/shared-types';
import { Button, Field, PageHeader } from '../../components/ui';
import { activeMockUser, canSchedule, canView, mockCalendarEvents, siteContent, type UserRole } from '../../mocks';
import { CalendarHeaderControls, CalendarMonthNavigator, SelectedDateSidebar } from './sections';
import styles from './page.module.scss';

export default function CalendarPage() {
  if (!canView('calendar', activeMockUser.role)) return null;
  const [events, setEvents] = useState<CalendarEventDto[]>(mockCalendarEvents);
  const [role, setRole] = useState<UserRole>(activeMockUser.role);
  const [selectedDate, setSelectedDate] = useState<string | null>('2026-04-20');
  const [rescheduleEvt, setRescheduleEvt] = useState<CalendarEventDto | null>(null);
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');
  const [view, setView] = useState<'month' | 'week'>('month');
  const [year, setYear] = useState(2026);
  const [month, setMonth] = useState(3);
  const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August'];
  const DAYS = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  const visibleEvents = useMemo(
    () => events.filter((eventItem) => (role === 'student' ? eventItem.studentId === activeMockUser.id : true)),
    [events, role],
  );
  const eventsOnDate = (date: string) => visibleEvents.filter((eventItem) => eventItem.date === date);
  const selectedEvents = selectedDate ? eventsOnDate(selectedDate) : [];
  const daysCount = new Date(year, month + 1, 0).getDate();
  const firstDow = ((new Date(year, month, 1).getDay() + 6) % 7) as number;

  const weekStart = (() => {
    const base = selectedDate ? new Date(selectedDate) : new Date(year, month, 1);
    const dow = base.getDay() === 0 ? 6 : base.getDay() - 1;
    const start = new Date(base);
    start.setDate(base.getDate() - dow);
    return start;
  })();
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const date = new Date(weekStart);
    date.setDate(weekStart.getDate() + i);
    return date;
  });
  const hours = Array.from({ length: 12 }, (_, i) => i + 8);
  const typeColor: Record<string, string> = { grammar: 'Blue', vocabulary: 'Green', speaking: 'Amber', listening: 'Purple' };
  const typeLabel: Record<string, string> = { grammar: 'Grammar', vocabulary: 'Vocabulary', speaking: 'Speaking', listening: 'Listening' };

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title={siteContent.calendar.title}
        subtitle={
          role === 'student'
            ? 'Your personal lesson schedule'
            : `Teacher view — all students (${[...new Set(events.map((eventItem) => eventItem.studentId))].length} students)`
        }
        actions={<CalendarHeaderControls view={view} setView={setView} role={role} setRole={setRole} />}
      />

      <div className={styles.calLayout}>
        <div className={styles.calMain}>
          <CalendarMonthNavigator
            monthLabel={`${MONTHS[month]} ${year}`}
            onPrev={() => {
              if (month === 0) {
                setYear((y) => y - 1);
                setMonth(11);
              } else setMonth((m) => m - 1);
            }}
            onNext={() => {
              if (month === 11) {
                setYear((y) => y + 1);
                setMonth(0);
              } else setMonth((m) => m + 1);
            }}
          />

          {view === 'month' && (
            <div className={styles.monthGrid}>
              {DAYS.map((day) => (
                <div key={day} className={styles.dayName}>
                  {day}
                </div>
              ))}
              {Array.from({ length: firstDow }).map((_, i) => (
                <div key={`e${i}`} className={styles.emptyCell} />
              ))}
              {Array.from({ length: daysCount }, (_, i) => {
                const day = i + 1;
                const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                const dayEvents = eventsOnDate(dateStr);
                const isSelected = selectedDate === dateStr;
                const isToday = dateStr === '2026-04-20';
                return (
                  <div
                    key={day}
                    className={`${styles.dayCell} ${isSelected ? styles.dayCellSelected : ''} ${isToday ? styles.dayCellToday : ''}`}
                    onClick={() => setSelectedDate(dateStr)}
                  >
                    <span className={styles.dayNum}>{day}</span>
                    <div className={styles.dayDots}>
                      {dayEvents.slice(0, 3).map((eventItem) => (
                        <div
                          key={eventItem.id}
                          className={`${styles.dayDot} ${styles[`dot${typeColor[eventItem.type]}`]}`}
                        />
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {view === 'week' && (
            <div className={styles.weekView}>
              <div className={styles.weekHeader}>
                <div className={styles.weekTimeCol} />
                {weekDays.map((date) => {
                  const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
                  const isToday = dateStr === '2026-04-20';
                  const isSelected = selectedDate === dateStr;
                  return (
                    <div
                      key={dateStr}
                      className={`${styles.weekDayHeader} ${isToday ? styles.weekDayToday : ''} ${isSelected ? styles.weekDaySelected : ''}`}
                      onClick={() => setSelectedDate(dateStr)}
                    >
                      <div className={styles.weekDayName}>{DAYS[date.getDay() === 0 ? 6 : date.getDay() - 1]}</div>
                      <div className={styles.weekDayNum}>{date.getDate()}</div>
                    </div>
                  );
                })}
              </div>
              <div className={styles.weekBody}>
                {hours.map((hour) => (
                  <div key={hour} className={styles.weekRow}>
                    <div className={styles.weekHour}>{hour}:00</div>
                    {weekDays.map((date) => {
                      const dateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
                      const slotEvents = eventsOnDate(dateStr).filter((eventItem) => parseInt(eventItem.time, 10) === hour);
                      return (
                        <div key={dateStr} className={styles.weekCell}>
                          {slotEvents.map((eventItem) => (
                            <div key={eventItem.id} className={`${styles.weekEvt} ${styles[`evt${typeColor[eventItem.type]}`]}`}>
                              <div className={styles.weekEvtTitle}>{eventItem.title}</div>
                              <div className={styles.weekEvtTime}>{eventItem.time} · 55 min</div>
                            </div>
                          ))}
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <SelectedDateSidebar
          selectedDate={selectedDate}
          selectedEvents={selectedEvents}
          role={role}
          typeColor={typeColor}
          typeLabel={typeLabel}
          onReschedule={(eventItem) => {
            setRescheduleEvt(eventItem);
            setNewDate(eventItem.date);
            setNewTime(eventItem.time);
          }}
        />
      </div>

      {rescheduleEvt && (
        <div className={styles.modalOverlay} onClick={() => setRescheduleEvt(null)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.modalTitle}>{role === 'teacher' ? 'Reschedule lesson' : 'Request reschedule'}</div>
            <div className={styles.modalLesson}>{rescheduleEvt.title}</div>
            <div className={styles.modalFields}>
              <div className={styles.fieldGroup}>
                <label className={styles.fieldLabel}>New date</label>
                <Field type="date" className={styles.fieldInput} value={newDate} onChange={(e) => setNewDate(e.target.value)} />
              </div>
              <div className={styles.fieldGroup}>
                <label className={styles.fieldLabel}>New time</label>
                <Field type="time" className={styles.fieldInput} value={newTime} onChange={(e) => setNewTime(e.target.value)} />
              </div>
            </div>
            <div className={styles.modalActions}>
              <Button type="button" className={styles.modalCancelBtn} onClick={() => setRescheduleEvt(null)}>
                Cancel
              </Button>
              <Button
                type="button"
                className={styles.modalConfirmBtn}
                onClick={() => {
                  if (!rescheduleEvt) return;
                  setEvents((prev) =>
                    prev.map((eventItem) =>
                      eventItem.id === rescheduleEvt.id ? { ...eventItem, date: newDate, time: newTime, status: 'pending' } : eventItem,
                    ),
                  );
                  setRescheduleEvt(null);
                }}
              >
                {canSchedule('calendar', role) ? 'Confirm reschedule' : 'Send request'}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
